INSERT INTO private_schools (id, name, image, location, capacity, teachersCount, type, lessons, lessonHours, schoolHours, parentReviewText, reviewerName, rating, sector, averageClassSize, branchesCount, reviewsCount, imagesCount, deals, monthlyPrice, classSizeCategory, educationSystem, physicalFacilities, services, activities, languages) VALUES ('school-1', 'İstanbul Anadolu Bilim Koleji', 'https://images.unsplash.com/photo-1541339907198-e08756dedf3f?auto=format&fit=crop&w=600&q=80', 'İstanbul / Kadıköy / Göztepe', 450, 38, 'Lise', '["Fen Olimpiyatları","Robotik Kodlama","Girişimcilik ve Finans"]', 'Haftalık 42 Ders Saati', '08:30 - 16:30 (Tam Zamanlı)', 'Oğlumuz bu okula başladığından beri bilim olimpiyatlarına merak saldı. Robotik laboratuvarları ve öğretmen kalitesi birinci sınıf.', 'Ahmet & Canan Yeşildere', 4.9, 'Özel Okul', 16, 5, 44, 12, '["%30 İndirim","Kampanya","Yaz Okulu"]', 12500, '1-20 Kişilik', 'Çoklu Zeka Modeli', '["Yemekhane","Bilgisayar Laboratuvarı","Kapalı Spor Salonu","Konferans Salonu"]', '["Güvenlik","Rehberlik","Servis"]', '["Futbol","Basketbol","Masa Tenisi"]', '["İngilizce","Almanca"]');
INSERT INTO private_schools (id, name, image, location, capacity, teachersCount, type, lessons, lessonHours, schoolHours, parentReviewText, reviewerName, rating, sector, averageClassSize, branchesCount, reviewsCount, imagesCount, deals, monthlyPrice, classSizeCategory, educationSystem, physicalFacilities, services, activities, languages) VALUES ('school-2', 'Avrupa Lisan ve Sanat Koleji', 'https://images.unsplash.com/photo-1523050854058-8df90110c9f1?auto=format&fit=crop&w=600&q=80', 'İstanbul / Beşiktaş / Bebek', 320, 29, 'İlkokul', '["Akıcı İngilizce (Cambridge)","B2 Fransızca / Almanca","Drama ve Yağlı Boya"]', 'Haftalık 36 Ders Saati', '09:00 - 15:30 (Yarım/Tam Opsiyonu)', 'İki dilli eğitim iddiasını gerçekten hakkıyla yerine getiren nadir okullardan. Dönem sonlarında harika tiyatro oyunları sahneliyorlar.', 'Yasemin Güneş', 4.7, 'Özel Okul', 12, 3, 32, 8, '["%15 Erken Kayıt","Kampanya"]', 14000, '1-15 Kişilik', 'Montessori Eğitimi', '["Yemekhane","Havuz","Bilgisayar Laboratuvarı","Konferans Salonu"]', '["Güvenlik","Rehberlik","Yaz Okulu","Organik Beslenme"]', '["Voleybol","Judo","Masa Tenisi"]', '["İngilizce","Fransızca","Almanca"]');
INSERT INTO private_schools (id, name, image, location, capacity, teachersCount, type, lessons, lessonHours, schoolHours, parentReviewText, reviewerName, rating, sector, averageClassSize, branchesCount, reviewsCount, imagesCount, deals, monthlyPrice, classSizeCategory, educationSystem, physicalFacilities, services, activities, languages) VALUES ('school-3', 'Yedi Tepe Akıllı Doğa Koleji', 'https://images.unsplash.com/photo-1509062522246-3755977927d7?auto=format&fit=crop&w=600&q=80', 'İstanbul / Üsküdar / Kısıklı', 600, 45, 'Ortaokul', '["Yapay Zeka Destekli Derslikler","Ekolojik Tarım Atölyesi","Sürdürülebilir Tasarım"]', 'Haftalık 40 Ders Saati', '08:15 - 16:00', 'Bahçesindeki tarım uygulamaları ve çocukların kendi sebzelerini yetiştirmesi çok ince düşünülmüş bir vizyon. Tavsiye ederim.', 'Murat Kara', 4.8, 'Özel Okul', 18, 8, 56, 22, '["%20 İndirim","Yaz Okulu"]', 11000, '1-20 Kişilik', 'Eklektik Yaklaşım', '["Yemekhane","Havuz","Kapalı Spor Salonu","Futbol Sahası"]', '["Güvenlik","Rehberlik","Servis","Hafta sonu Eğitim","Organik Beslenme"]', '["Futbol","Voleybol","Basketbol","Su Topu"]', '["İngilizce","İspanyolca","İtalyanca"]');
INSERT INTO private_schools (id, name, image, location, capacity, teachersCount, type, lessons, lessonHours, schoolHours, parentReviewText, reviewerName, rating, sector, averageClassSize, branchesCount, reviewsCount, imagesCount, deals, monthlyPrice, classSizeCategory, educationSystem, physicalFacilities, services, activities, languages) VALUES ('school-4', 'Kısıklı Devlet Klasik Anadolu Lisesi', 'https://images.unsplash.com/photo-1541339907198-e08756dedf3f?auto=format&fit=crop&w=600&q=80', 'İstanbul / Üsküdar / Kısıklı', 700, 48, 'Lise', '["YKS Nokta Atışı","Edebiyat Atölyeleri","Kütüphane Araştırmaları"]', 'Haftalık 35 Ders Saati', '08:00 - 15:30', 'Devlet okulu olmasına rağmen son derece disiplinli, öğretmenleri idealist ve canla başla çalışıyorlar.', 'Metin Sancaklı', 4.5, 'Devlet Okulu', 24, 1, 19, 6, '[]', 400, '+20 Kişilik', 'MEB Odaklı Eğitim', '["Yemekhane","Kapalı Spor Salonu","Konferans Salonu"]', '["Güvenlik","Rehberlik"]', '["Futbol","Voleybol","Basketbol"]', '["İngilizce","Almanca"]');
INSERT INTO private_schools (id, name, image, location, capacity, teachersCount, type, lessons, lessonHours, schoolHours, parentReviewText, reviewerName, rating, sector, averageClassSize, branchesCount, reviewsCount, imagesCount, deals, monthlyPrice, classSizeCategory, educationSystem, physicalFacilities, services, activities, languages) VALUES ('school-5', 'Mutlu Yumurcaklar Montessori Anaokulu', 'https://images.unsplash.com/photo-1576086213369-97a306d36557?auto=format&fit=crop&w=600&q=80', 'İstanbul / Maltepe / Küçükyalı', 120, 12, 'Anaokulu', '["Duyu Gelişimi","Ahşap Oyuncak Atölyesi","Müzik ve Ritim"]', 'Haftalık 30 Ders Saati', '08:30 - 17:00 (Tam Gün)', 'Kızımızın bireysel becerileri o kadar gelişti ki, kendi yemeğini kendi hazırlıyor ve her şeyi topluyor. Montessori felsefesini tam uyguluyorlar.', 'Melis Atasoy', 4.9, 'Özel Okul', 8, 2, 15, 9, '["%10 Kardeş İndirimi","Yaz Okulu"]', 9500, '1-10 kişilik', 'Montessori Eğitimi', '["Yemekhane","Kapalı Spor Salonu"]', '["Güvenlik","Rehberlik","Organik Beslenme"]', '["Judo","Masa Tenisi"]', '["İngilizce"]');
INSERT INTO special_courses (id, name, image, type, location, capacity, teachersCount, classes, hoursPerWeek, priceRange, parentReviewText, reviewerName, rating, branchesCount, averageClassSize) VALUES ('spec-1', 'Metropol LGS & YKS Hazırlık Akademisi', 'https://images.unsplash.com/photo-1434030216411-0b793f4b4173?auto=format&fit=crop&w=600&q=80', 'YKS', 'İstanbul / Ataşehir / Atatürk Mah.', 150, 14, '["Sayısal Derece Grubu","Eşit Ağırlık Nokta Atışı","Geometri Pratik Atölyesi"]', 'Haftalık 16 Saat Etüt + Deneme', '₺125.000', 'Kızım geçen sene YKS sayısal alanda ilk 15 bin içerisine girdi. Rehberlik ve deneme takip sistemleri muhteşemdi.', 'Süreyya Özcan', 4.9, 5, 6);
INSERT INTO special_courses (id, name, image, type, location, capacity, teachersCount, classes, hoursPerWeek, priceRange, parentReviewText, reviewerName, rating, branchesCount, averageClassSize) VALUES ('spec-2', 'Vera Güzel Sanatlar & Konservatuar Atölyesi', 'https://images.unsplash.com/photo-1513364776144-60967b0f800f?auto=format&fit=crop&w=600&q=80', 'Yetenek Sınavları', 'İstanbul / Kadıköy / Göztepe', 80, 8, '["Güzel Sanatlara Hazırlık Portfolyosu","Piyano & Keman Metodolojisi","Heykel / Seramik"]', 'Haftalık 12 Saat Birebir Atölye', '₺15.000', 'Resim yeteneği olan oğlumu Mimar Sinan sınavlarına hazırladılar ve kazandık! Eğitmenler inanılmaz ilgili.', 'Bülent Alkan', 5, 2, 4);
INSERT INTO special_courses (id, name, image, type, location, capacity, teachersCount, classes, hoursPerWeek, priceRange, parentReviewText, reviewerName, rating, branchesCount, averageClassSize) VALUES ('spec-3', 'Emniyet Direksiyon & Güvenli Sürüş Kursu', 'https://images.unsplash.com/photo-1517524206127-48bbd363f3d7?auto=format&fit=crop&w=600&q=80', 'Sürücü Kursu', 'İstanbul / Şişli / Merkez', 250, 12, '["Manuel/Otomatik Vites B Sınıfı","İleri Sürüş ve Defansif Teknikler","Simülasyonlu Park Eğitimi"]', 'Haftalık 16 Saat Direksiyon', '₺12.500', 'Sürüş fobisi olan biri olarak sabırla bana trafiği öğrettiler. İlk sınavda ehliyeti aldım, çok minnettarım.', 'Gizem Yıldız', 4.6, 3, 1);
INSERT INTO teachers (id, name, avatar, rating, commentsCount, experienceYears, experienceLabel, bio, preferredLocation, canCorporate, canOnline, canFaceToFace, tags, category) VALUES ('teacher-1', 'Mehmet Ali Öztürk', 'https://images.unsplash.com/photo-1500648767791-00dcc994a43e?auto=format&fit=crop&w=150&q=80', 4.9, 38, 12, '+10 Yıldan Fazla', '2015''ten beri aktif olarak programlama ve yapay zeka eğitimleri vermekteyim. Öğrencilerime teoriden çok iş bulmalarını sağlayacak pratik becerileri kazandırmaya odaklanıyorum.', 'İstanbul Anadolu Yakası', 1, 1, 1, '["Python","C#","Java","Mobil"]', 'Bilişim');
