INSERT INTO teachers (id, name, avatar, rating, commentsCount, experienceYears, experienceLabel, bio, preferredLocation, canCorporate, canOnline, canFaceToFace, tags, category) VALUES ('teacher-2', 'Elif Şahin', 'https://images.unsplash.com/photo-1544005313-94ddf0286df2?auto=format&fit=crop&w=150&q=80', 4.8, 24, 4, '1-5 Yıl', 'Yurt dışı deneyimli İngilizce ve Almanca öğretmeni. Akademik ve Sınav (IELTS, TOEFL) hazırlık odaklı, interaktif metodoloji ile her yaştan kitleye akıcılık kazandırıyorum.', 'İstanbul Avrupa Yakası', 1, 1, 0, '["İngilizce","Almanca","TOEFL"]', 'Dil');
