INSERT INTO teachers (id, name, avatar, rating, commentsCount, experienceYears, experienceLabel, bio, preferredLocation, canCorporate, canOnline, canFaceToFace, tags, category) VALUES ('teacher-3', 'Caner Şen', 'https://images.unsplash.com/photo-1519085360753-af0119f7cbe7?auto=format&fit=crop&w=150&q=80', 5, 15, 7, '+5 Yıldan Fazla', 'TÜBİTAK Olimpiyatlarında derece sahibi Matematik Eğitmeni. Öğrencilerin ders sevgisini artıracak özel formüller ve LGS / YKS taktikleriyle yüksek puan garantili öğretim.', 'İstanbul Anadolu Yakası', 0, 1, 1, '["Matematik","LGS","YKS"]', 'Lise/Sınav');
