INSERT INTO teachers (id, name, avatar, rating, commentsCount, experienceYears, experienceLabel, bio, preferredLocation, canCorporate, canOnline, canFaceToFace, tags, category) VALUES ('teacher-4', 'Selin Aktaş', 'https://images.unsplash.com/photo-1573496359142-b8d87734a5a2?auto=format&fit=crop&w=150&q=80', 4.6, 6, 1, 'Yeni', 'Sanat akademisi mezunu, çocuk yaş grubu ve yetişkinler için yağlı boya ve dijital illüstrasyon mentörü. İçinizdeki sanatçıyı keşfetmek için harika bir adımla başlıyoruz.', 'İstanbul Beyoğlu', 1, 0, 1, '["Sanat","Resim","Figma","İllüstrasyon"]', 'Sanat');
