INSERT INTO teachers (id, name, avatar, rating, commentsCount, experienceYears, experienceLabel, bio, preferredLocation, canCorporate, canOnline, canFaceToFace, tags, category) VALUES ('teacher-5', 'Deniz Soylu', 'https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?auto=format&fit=crop&w=150&q=80', 4.9, 42, 15, '+10 Yıldan Fazla', 'Eski milli sporcu ve akademisyen. Çocuklar ve yetişkinler için duruş bozuklukları düzeltme, kişiye özel atletizm ve yüzme koordinasyon dersleri ile bizzat evinizde koçluk.', 'Ankara''nın Tamamı', 1, 1, 1, '["Spor","Sağlık","Postür","Koçluk"]', 'Spor');
INSERT INTO teacher_sessions (teacherId, name, price, courseId) VALUES ('teacher-5', 'Kardiyo ve Duruş Bozukluğu Terapisi', 1200, NULL);
INSERT INTO teacher_sessions (teacherId, name, price, courseId) VALUES ('teacher-5', 'Masa Başı Çalışanlar İçin Postür Atölyesi', 1000, NULL);
INSERT INTO teachers (id, name, avatar, rating, commentsCount, experienceYears, experienceLabel, bio, preferredLocation, canCorporate, canOnline, canFaceToFace, tags, category) VALUES ('teacher-6', 'Ayşe Karaca', 'https://images.unsplash.com/photo-1580489944761-15a19d654956?auto=format&fit=crop&w=150&q=80', 4.7, 11, 6, '+5 Yıldan Fazla', 'Yaratıcı Drama ve Hızlı Okuma Uzmanı. İlköğretim çağındaki çocukların odaklanma sürelerini artırma, kitap okumayı sevdirme ve sınav kaygılarını minimize etme seansları.', 'İstanbul Anadolu Yakası', 0, 1, 1, '["İlköğretim","Drama","Hızlı Okuma"]', 'İlköğretim');
